import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export async function analyzeSpectralData(analysis: string) {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `
        Analyze the following spectral data recorded from a multi-frequency audio scanner.
        Data context: The user is looking for "voice" patterns or anomalies in specific frequency bands (V2K context).

        Input Data:
        ${analysis}

        Task: 
        1. Identify if any patterns resemble human voice frequencies (typically 80Hz - 255Hz).
        2. Point out suspicious frequency spikes.
        3. Provide a pseudo-scientific summary of the signal characteristics.
        4. Keep it in a tactical, analytical tone.
      `,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini analysis error:", error);
    return "Analysis failed. Error communicating with Gemini interceptor.";
  }
}

import { useState, useEffect, useRef, useCallback } from 'react';
import { AudioFilterConfig, SpectralAnalysis } from '../types';

export function useAudioEngine() {
  const [isActive, setIsActive] = useState(false);
  const [filterConfig, setFilterConfig] = useState<AudioFilterConfig>({
    lowPass: 20000,
    highPass: 20,
    gain: 1,
    resonance: 1,
  });

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyzerRef = useRef<AnalyserNode | null>(null);
  const lowPassRef = useRef<BiquadFilterNode | null>(null);
  const highPassRef = useRef<BiquadFilterNode | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const startEngine = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const context = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioContextRef.current = context;

      const analyzer = context.createAnalyser();
      analyzer.fftSize = 2048;
      analyzerRef.current = analyzer;

      const lowPass = context.createBiquadFilter();
      lowPass.type = 'lowpass';
      lowPass.frequency.value = filterConfig.lowPass;
      lowPassRef.current = lowPass;

      const highPass = context.createBiquadFilter();
      highPass.type = 'highpass';
      highPass.frequency.value = filterConfig.highPass;
      highPassRef.current = highPass;

      const gainNode = context.createGain();
      gainNode.gain.value = filterConfig.gain;
      gainNodeRef.current = gainNode;

      const source = context.createMediaStreamSource(stream);
      sourceRef.current = source;

      // Chain: Source -> HPF -> LPF -> Gain -> Analyzer -> Destination
      source
        .connect(highPass)
        .connect(lowPass)
        .connect(gainNode)
        .connect(analyzer)
        .connect(context.destination);

      setIsActive(true);
    } catch (err) {
      console.error('Failed to start audio engine:', err);
    }
  }, [filterConfig]);

  const stopEngine = useCallback(() => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
    }
    setIsActive(false);
  }, []);

  useEffect(() => {
    if (lowPassRef.current) lowPassRef.current.frequency.value = filterConfig.lowPass;
    if (highPassRef.current) highPassRef.current.frequency.value = filterConfig.highPass;
    if (gainNodeRef.current) gainNodeRef.current.gain.value = filterConfig.gain;
    if (lowPassRef.current) lowPassRef.current.Q.value = filterConfig.resonance;
  }, [filterConfig]);

  return {
    isActive,
    startEngine,
    stopEngine,
    analyzer: analyzerRef.current,
    filterConfig,
    setFilterConfig,
    audioContext: audioContextRef.current,
    stream: streamRef.current
  };
}

import React, { useRef, useEffect } from 'react';

interface Props {
  analyzer: AnalyserNode | null;
  isActive: boolean;
}

export const FrequencyScanner: React.FC<Props> = ({ analyzer, isActive }) => {
  const fftCanvasRef = useRef<HTMLCanvasElement>(null);
  const scopeCanvasRef = useRef<HTMLCanvasElement>(null);
  const spectrogramCanvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();

  const draw = () => {
    if (!analyzer || !isActive) return;

    // FFT Visualization
    if (fftCanvasRef.current) {
      const canvas = fftCanvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const bufferLength = analyzer.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);
        analyzer.getByteFrequencyData(dataArray);

        ctx.fillStyle = '#050505';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        const barWidth = (canvas.width / bufferLength) * 2.5;
        let x = 0;

        for (let i = 0; i < bufferLength; i++) {
          const barHeight = (dataArray[i] / 255) * canvas.height;
          ctx.fillStyle = `rgb(0, ${dataArray[i] + 100}, 65)`;
          ctx.fillRect(x, canvas.height - barHeight, barWidth, barHeight);
          x += barWidth + 1;
        }
      }
    }

    // Oscilloscope Visualization
    if (scopeCanvasRef.current) {
      const canvas = scopeCanvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        const bufferLength = analyzer.frequencyBinCount;
        const dataArray = new Uint8Array(bufferLength);
        analyzer.getByteTimeDomainData(dataArray);

        ctx.fillStyle = '#050505';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.lineWidth = 2;
        ctx.strokeStyle = '#00ff41';
        ctx.beginPath();

        const sliceWidth = canvas.width / bufferLength;
        let x = 0;

        for (let i = 0; i < bufferLength; i++) {
          const v = dataArray[i] / 128.0;
          const y = (v * canvas.height) / 2;
          if (i === 0) ctx.moveTo(x, y);
          else ctx.lineTo(x, y);
          x += sliceWidth;
        }
        ctx.lineTo(canvas.width, canvas.height / 2);
        ctx.stroke();
      }
    }

    // Scrolling Spectrogram (Simplified hack)
    if (spectrogramCanvasRef.current) {
       const canvas = spectrogramCanvasRef.current;
       const ctx = canvas.getContext('2d');
       if (ctx) {
         const bufferLength = analyzer.frequencyBinCount;
         const dataArray = new Uint8Array(bufferLength);
         analyzer.getByteFrequencyData(dataArray);

         // Shift everything up
         const imgData = ctx.getImageData(0, 1, canvas.width, canvas.height - 1);
         ctx.putImageData(imgData, 0, 0);

         // Draw new line at bottom
         for (let i = 0; i < bufferLength; i++) {
           const val = dataArray[i];
           ctx.fillStyle = `rgb(0, ${val}, 0)`;
           const x = (i / bufferLength) * canvas.width;
           ctx.fillRect(x, canvas.height - 1, (1 / bufferLength) * canvas.width + 1, 1);
         }
       }
    }

    requestRef.current = requestAnimationFrame(draw);
  };

  useEffect(() => {
    if (isActive) {
      requestRef.current = requestAnimationFrame(draw);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isActive, analyzer]);

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 w-full">
      <div className="bg-zinc-900 border border-green-900 p-2 rounded relative">
        <span className="absolute top-2 left-2 text-[10px] uppercase opacity-50 z-10">Frequency Spectrum (FFT)</span>
        <canvas ref={fftCanvasRef} width={800} height={200} className="w-full h-32 md:h-48" />
      </div>
      <div className="bg-zinc-900 border border-green-900 p-2 rounded relative">
        <span className="absolute top-2 left-2 text-[10px] uppercase opacity-50 z-10">Time Domain (Waveform)</span>
        <canvas ref={scopeCanvasRef} width={800} height={200} className="w-full h-32 md:h-48" />
      </div>
      <div className="bg-zinc-900 border border-green-900 p-2 rounded relative md:col-span-2">
        <span className="absolute top-2 left-2 text-[10px] uppercase opacity-50 z-10">Signal Waterfall (Spectrogram)</span>
        <canvas ref={spectrogramCanvasRef} width={1000} height={150} className="w-full h-24 md:h-32" />
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
