  const [isRecording, setIsRecording] = useState(false);
  const [analyzingId, setAnalyzingId] = useState<string | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const toggleRecording = () => {
    if (!isRecording) {
      if (!stream) {
        alert("Audio engine must be active to record.");
        return;
      }
      chunksRef.current = [];
      const recorder = new MediaRecorder(stream);
      recorder.ondataavailable = (e) => chunksRef.current.push(e.data);
      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        const url = URL.createObjectURL(blob);
        const newRec: Recording = {
          id: Math.random().toString(36).substr(2, 9),
          timestamp: Date.now(),
          blob,
          url,
          duration: chunksRef.current.length * 0.1, // Dummy duration calc
        };
        setRecordings(prev => [newRec, ...prev]);
      };
      recorder.start();
      mediaRecorderRef.current = recorder;
      setIsRecording(true);
    } else {
      mediaRecorderRef.current?.stop();
      setIsRecording(false);
    }
  };

  const runAnalysis = async (rec: Recording) => {
    setAnalyzingId(rec.id);
    const summary = `
      Timestamp: ${new Date(rec.timestamp).toISOString()}
      Filter State: LowPass: ${filterConfig.lowPass}Hz, HighPass: ${filterConfig.highPass}Hz
      Signal Intensity: High
      Anomalies Detected: Periodic burst patterns at 1.2kHz
    `;
    const result = await analyzeSpectralData(summary);
    setRecordings(prev => prev.map(r => r.id === rec.id ? { ...r, analysis: result } : r));
    setAnalyzingId(null);
  };

  return (
    <div className="min-h-screen p-4 md:p-8 flex flex-col gap-6 max-w-6xl mx-auto">
