        </div>
        <div className="flex gap-2 w-full md:w-auto">
          {!isActive ? (
            <button 
              onClick={startEngine}
              className="bg-green-950 hover:bg-green-900 border border-green-500 text-green-500 px-6 py-2 rounded text-sm font-bold transition-all w-full md:w-auto"
            >
              INITIALIZE SCANNER
            </button>
          ) : (
            <button 
              onClick={stopEngine}
              className="bg-red-950 hover:bg-red-900 border border-red-500 text-red-500 px-6 py-2 rounded text-sm font-bold transition-all w-full md:w-auto"
            >
              TERMINATE SCAN
            </button>
          )}
        </div>
      </header>

      {/* Main Grid */}
      <main className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column: Visualizers */}
        <div className="lg:col-span-2 flex flex-col gap-6">
          <FrequencyScanner analyzer={analyzer} isActive={isActive} />

          {/* Controls */}
          <section className="bg-zinc-900 border border-green-900 p-6 rounded grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-4">
              <h3 className="text-sm font-bold text-green-600 mb-2 uppercase border-b border-green-900 pb-1">Filter Arrays</h3>
              <div>
                <label className="text-[10px] text-green-800 uppercase block mb-1">High-Pass Frequency (Hz)</label>
                <input 
                  type="range" min="20" max="20000" step="1" 
                  value={filterConfig.highPass} 
                  onChange={(e) => setFilterConfig(p => ({ ...p, highPass: Number(e.target.value) }))}
                  className="w-full accent-green-500 bg-zinc-800 h-1 rounded-full appearance-none"
                />
                <div className="flex justify-between text-[10px] mt-1 text-green-900">
                  <span>20Hz</span>
                  <span className="text-green-500 font-bold">{filterConfig.highPass} Hz</span>
                  <span>20kHz</span>
                </div>
              </div>
              <div>
                <label className="text-[10px] text-green-800 uppercase block mb-1">Low-Pass Frequency (Hz)</label>
                <input 
                  type="range" min="20" max="20000" step="1" 
                  value={filterConfig.lowPass} 
                  onChange={(e) => setFilterConfig(p => ({ ...p, lowPass: Number(e.target.value) }))}
                  className="w-full accent-green-500 bg-zinc-800 h-1 rounded-full appearance-none"
                />
                <div className="flex justify-between text-[10px] mt-1 text-green-900">
                  <span>20Hz</span>
                  <span className="text-green-500 font-bold">{filterConfig.lowPass} Hz</span>
                  <span>20kHz</span>
                </div>
              </div>
            </div>

            <div className="space-y-4">
              <h3 className="text-sm font-bold text-green-600 mb-2 uppercase border-b border-green-900 pb-1">Signal Processing</h3>
              <div>
                <label className="text-[10px] text-green-800 uppercase block mb-1">Gain Boost (dB)</label>
                <input 
                  type="range" min="0" max="5" step="0.1" 
                  value={filterConfig.gain} 
                  onChange={(e) => setFilterConfig(p => ({ ...p, gain: Number(e.target.value) }))}
                  className="w-full accent-green-500 bg-zinc-800 h-1 rounded-full appearance-none"
                />
              </div>
              <div>
                <label className="text-[10px] text-green-800 uppercase block mb-1">Filter Q (Resonance)</label>
                <input 
                  type="range" min="0.1" max="20" step="0.1" 
                  value={filterConfig.resonance} 
                  onChange={(e) => setFilterConfig(p => ({ ...p, resonance: Number(e.target.value) }))}
                  className="w-full accent-green-500 bg-zinc-800 h-1 rounded-full appearance-none"
                />
              </div>
              <button 
                onClick={toggleRecording}
                disabled={!isActive}
                className={`w-full py-3 rounded text-sm font-bold transition-all flex items-center justify-center gap-2 border ${
                  isRecording 
                    ? 'bg-red-950 border-red-500 text-red-500' 
                    : 'bg-green-950 border-green-500 text-green-500 hover:bg-green-900'
                } disabled:opacity-20`}
              >
                <div className={`w-2 h-2 rounded-full ${isRecording ? 'bg-red-500 animate-ping' : 'bg-green-500'}`} />
                {isRecording ? 'STOP CAPTURE' : 'CAPTURE SIGNAL'}
              </button>
            </div>
          </section>
        </div>

        {/* Right Column: Log & Analysis */}
        <aside className="bg-zinc-950 border border-green-900 rounded flex flex-col h-[500px] lg:h-auto">
          <div className="p-4 border-b border-green-900 bg-zinc-900 flex justify-between items-center">
            <h2 className="text-xs font-bold uppercase tracking-widest text-green-500">Capture Log</h2>
            <span className="text-[10px] text-green-800">{recordings.length} ENTRIES</span>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {recordings.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center opacity-20 text-center">
                <p className="text-xs">NO SIGNAL CAPTURED</p>
                <p className="text-[10px]">Awaiting input stream...</p>
              </div>
            ) : (
              recordings.map((rec) => (
                <div key={rec.id} className="border border-green-900 p-3 rounded bg-zinc-900 relative group overflow-hidden">
                  <div className="absolute top-0 left-0 w-1 h-full bg-green-500" />
                  <div className="flex justify-between items-start mb-2">
                    <div>
                      <p className="text-[10px] font-bold text-green-500 uppercase">ID: {rec.id}</p>
                      <p className="text-[9px] text-green-800">{new Date(rec.timestamp).toLocaleTimeString()}</p>
                    </div>
                    <button 
                      onClick={() => runAnalysis(rec)}
                      disabled={analyzingId === rec.id}
                      className="text-[9px] bg-green-900 hover:bg-green-800 text-white px-2 py-1 rounded transition-colors disabled:opacity-50"
                    >
                      {analyzingId === rec.id ? 'ANALYZING...' : 'AI ANALYSIS'}
                    </button>
                  </div>
                  <audio src={rec.url} controls className="w-full h-8 mt-2 contrast-125 invert saturate-200 grayscale brightness-75 rounded-none" />

                  {rec.analysis && (
                    <div className="mt-3 text-[10px] text-green-400 bg-black/40 p-2 border-t border-green-900 font-sans leading-relaxed">
                      <p className="font-bold text-green-600 mb-1 uppercase tracking-tighter">Gemini Intelligence Report:</p>
                      {rec.analysis}
