          </div>
        </aside>
      </main>

      <footer className="text-[10px] text-green-900 flex justify-between items-center border-t border-green-900 pt-4">
        <p>ENCRYPTED SIGNAL PROCESSING SYSTEM v3.4.0</p>
        <p>RELIANCE: HIGH | SPECTRAL_DENSITY: NOMINAL</p>
      </footer>
    </div>
  );
};

