import { useState, useEffect, useRef, useCallback } from 'react';
import { AudioFilterConfig, BandPower } from '../types';

export function useAudioEngine() {
  const [isActive, setIsActive] = useState(false);
  const [bandPowers, setBandPowers] = useState<BandPower[]>([
    { label: 'SUB', frequency: 60, power: 0 },
    { label: 'V2K_L', frequency: 440, power: 0 },
    { label: 'V2K_H', frequency: 2500, power: 0 },
    { label: 'S-WAVE', frequency: 8000, power: 0 },
  ]);
  const [filterConfig, setFilterConfig] = useState<AudioFilterConfig>({
    lowPass: 20000,
    highPass: 20,
    gain: 1,
    resonance: 1,
    v2kLock: false,
  });

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyzerRef = useRef<AnalyserNode | null>(null);
  const lowPassRef = useRef<BiquadFilterNode | null>(null);
  const highPassRef = useRef<BiquadFilterNode | null>(null);
  const v2kVoiceRef = useRef<BiquadFilterNode | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const rafRef = useRef<number>();

  const updateBandPowers = useCallback(() => {
    if (!analyzerRef.current || !isActive) return;
    const dataArray = new Uint8Array(analyzerRef.current.frequencyBinCount);
    analyzerRef.current.getByteFrequencyData(dataArray);
    const sampleRate = audioContextRef.current?.sampleRate || 44100;
    const fftSize = analyzerRef.current.fftSize;

    const newPowers = bandPowers.map(band => {
      const bin = Math.floor(band.frequency / (sampleRate / fftSize));
      return { ...band, power: dataArray[bin] / 255 };
    });
    setBandPowers(newPowers);
    rafRef.current = requestAnimationFrame(updateBandPowers);
  }, [isActive, bandPowers]);

  const startEngine = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const context = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioContextRef.current = context;

      const analyzer = context.createAnalyser();
      analyzer.fftSize = 2048;
      analyzerRef.current = analyzer;

      const lowPass = context.createBiquadFilter();
      lowPass.type = 'lowpass';
      lowPassRef.current = lowPass;

      const highPass = context.createBiquadFilter();
      highPass.type = 'highpass';
      highPassRef.current = highPass;

      const v2kVoice = context.createBiquadFilter();
      v2kVoice.type = 'bandpass';
      v2kVoice.frequency.value = 1200;
      v2kVoice.Q.value = 10;
      v2kVoiceRef.current = v2kVoice;

      const gainNode = context.createGain();
      gainNodeRef.current = gainNode;

      const source = context.createMediaStreamSource(stream);
      sourceRef.current = source;

      // Dynamic Re-routing based on V2K Lock
      source.connect(highPass);
      highPass.connect(lowPass);
      lowPass.connect(v2kVoice);
      v2kVoice.connect(gainNode);
      gainNode.connect(analyzer);
      analyzer.connect(context.destination);

      setIsActive(true);
      rafRef.current = requestAnimationFrame(updateBandPowers);
    } catch (err) {
      console.error('Failed to start audio engine:', err);
    }
  }, [updateBandPowers]);

  const stopEngine = useCallback(() => {
    if (streamRef.current) streamRef.current.getTracks().forEach(track => track.stop());
    if (audioContextRef.current) audioContextRef.current.close();
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
    setIsActive(false);
  }, []);

  useEffect(() => {
    if (!isActive) return;
    if (lowPassRef.current) lowPassRef.current.frequency.value = filterConfig.lowPass;
    if (highPassRef.current) highPassRef.current.frequency.value = filterConfig.highPass;
    if (gainNodeRef.current) gainNodeRef.current.gain.value = filterConfig.gain;

    if (v2kVoiceRef.current) {
      if (filterConfig.v2kLock) {
        // Human voice optimization: Band-pass 300-3400Hz
        v2kVoiceRef.current.frequency.value = 1850; 
        v2kVoiceRef.current.Q.value = 0.5; // Wider for voices
      } else {
        // Passthrough or specific resonance
        v2kVoiceRef.current.frequency.value = 10000;
        v2kVoiceRef.current.Q.value = 0.1;
      }
    }
  }, [filterConfig, isActive]);

  return {
    isActive,
    startEngine,
    stopEngine,
    analyzer: analyzerRef.current,
    filterConfig,
    setFilterConfig,
    bandPowers,
    audioContext: audioContextRef.current,
    stream: streamRef.current
  };
}

import React, { useState, useRef } from 'react';
import { useAudioEngine } from './hooks/useAudioEngine';
import { FrequencyScanner } from './components/FrequencyScanner';
import { Recording } from './types';
import { analyzeSpectralData } from './services/geminiService';

const App: React.FC = () => {
  const { 
    isActive, 
    startEngine, 
    stopEngine, 
    analyzer, 
    filterConfig, 
    setFilterConfig, 
    bandPowers,
    stream 
  } = useAudioEngine();

  const [recordings, setRecordings] = useState<Recording[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [analyzingId, setAnalyzingId] = useState<string | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);

  const toggleRecording = () => {
    if (!isRecording) {
      if (!stream) return;
      chunksRef.current = [];
      const recorder = new MediaRecorder(stream);
      recorder.ondataavailable = (e) => chunksRef.current.push(e.data);
      recorder.onstop = () => {
        const blob = new Blob(chunksRef.current, { type: 'audio/webm' });
        const url = URL.createObjectURL(blob);
        const newRec: Recording = {
          id: `REC-${Math.random().toString(36).substr(2, 5).toUpperCase()}`,
          timestamp: Date.now(),
          blob,
          url,
          duration: 0,
        };
        setRecordings(prev => [newRec, ...prev]);
      };
      recorder.start();
      mediaRecorderRef.current = recorder;
      setIsRecording(true);
    } else {
      mediaRecorderRef.current?.stop();
      setIsRecording(false);
    }
  };

  const runAnalysis = async (rec: Recording) => {
    setAnalyzingId(rec.id);
    const summary = `
      V2K Intercept Log: ${rec.id}
      Frequency Lock Status: ${filterConfig.v2kLock ? 'V2K_ISOLATION_ACTIVE' : 'WIDEBAND'}
      Observed Peak Frequencies: ${bandPowers.map(b => `${b.label}:${(b.power * 100).toFixed(0)}%`).join(', ')}
      Objective: Isolate embedded vocal transmissions.
    `;
    const result = await analyzeSpectralData(summary);
    setRecordings(prev => prev.map(r => r.id === rec.id ? { ...r, analysis: result } : r));
    setAnalyzingId(null);
  };

  return (
    <div className="min-h-screen p-4 md:p-6 flex flex-col gap-4 max-w-7xl mx-auto">
      <header className="flex flex-col md:flex-row justify-between items-end border-b-2 border-green-500/30 pb-4">
        <div className="flex flex-col">
          <div className="flex items-center gap-3">
            <h1 className="text-4xl font-black text-green-500 tracking-tighter italic">V2K SIGNAL-X</h1>
            <div className={`px-2 py-0.5 text-[10px] rounded font-bold ${isActive ? 'bg-green-500 text-black animate-pulse' : 'bg-red-500 text-white'}`}>
              {isActive ? 'SYSTEM_ARMED' : 'OFFLINE'}
            </div>
          </div>
          <p className="text-[10px] text-green-700 font-mono tracking-widest mt-1">SIMULTANEOUS MULTI-BAND INTERCEPTION ENGINE</p>
        </div>
        <div className="flex gap-2 mt-4 md:mt-0">
          <button 
            onClick={isActive ? stopEngine : startEngine}
            className={`px-8 py-2 text-xs font-black tracking-widest transition-all border-2 ${
              isActive ? 'border-red-500 text-red-500 hover:bg-red-500/10' : 'border-green-500 text-green-500 hover:bg-green-500/10'
            }`}
          >
            {isActive ? 'DEACTIVATE' : 'BOOT_INTERCEPTOR'}
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 xl:grid-cols-12 gap-6 flex-1">
        {/* Left Column: Frequency Map */}
        <div className="xl:col-span-2 bg-zinc-900/50 border border-green-900/50 p-4 rounded flex flex-col gap-4">
          <h3 className="text-[10px] font-black text-green-600 uppercase border-b border-green-900 pb-2">Band Monitoring</h3>
          <div className="flex flex-col gap-6 justify-around flex-1 py-4">
            {bandPowers.map(band => (
              <div key={band.label} className="flex flex-col gap-1">
                <div className="flex justify-between text-[9px] font-bold">
                  <span className="text-green-800">{band.label}</span>
                  <span className={band.power > 0.7 ? 'text-red-500' : 'text-green-500'}>
                    {(band.power * 100).toFixed(0)}%
                  </span>
                </div>
                <div className="h-2 w-full bg-zinc-800 rounded-full overflow-hidden border border-green-900/20">
                  <div 
                    className={`h-full transition-all duration-75 ${band.power > 0.7 ? 'bg-red-500 shadow-[0_0_10px_rgba(239,68,68,0.5)]' : 'bg-green-500'}`}
                    style={{ width: `${band.power * 100}%` }}
                  />
                </div>
                <span className="text-[8px] text-zinc-600 text-right italic">{band.frequency}Hz</span>
              </div>
            ))}
          </div>
          <div className="bg-black/50 p-2 rounded border border-green-900/30">
            <p className="text-[8px] text-green-700 leading-tight uppercase font-mono">
              [Auto-Scan] Tracking 256 unique frequency bins across 20-20,000Hz spectrum.
            </p>
          </div>
        </div>

        {/* Center: Main Visualizers */}
        <div className="xl:col-span-7 flex flex-col gap-4">
          <FrequencyScanner analyzer={analyzer} isActive={isActive} />

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="bg-zinc-900 p-4 border border-green-900 rounded">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xs font-black text-green-500 uppercase">V2K Voice Isolation</h3>
                <div 
                  onClick={() => setFilterConfig(p => ({ ...p, v2kLock: !p.v2kLock }))}
                  className={`w-12 h-6 rounded-full p-1 cursor-pointer transition-colors border ${filterConfig.v2kLock ? 'bg-green-600 border-green-400' : 'bg-zinc-800 border-zinc-700'}`}
                >
                  <div className={`w-4 h-4 bg-white rounded-full transition-transform ${filterConfig.v2kLock ? 'translate-x-6' : 'translate-x-0'}`} />
                </div>
              </div>
              <p className="text-[9px] text-green-800 mb-4 leading-relaxed">
                {filterConfig.v2kLock 
                  ? "SYSTEM_LOCK: Isolating human vocal frequencies (300-3400Hz). Background harmonic suppression active."
                  : "WIDE_SCAN: Monitoring all atmospheric audio perturbations. Full spectrum pass-through."}
              </p>
              <div className="grid grid-cols-2 gap-2">
                 <div className="bg-black/50 p-2 border border-green-900/20 rounded">
                    <span className="text-[8px] block text-green-900 uppercase">Resonance</span>
                    <input 
                      type="range" min="0.1" max="20" step="0.1" 
                      value={filterConfig.resonance} 
                      onChange={(e) => setFilterConfig(p => ({ ...p, resonance: Number(e.target.value) }))}
                      className="w-full accent-green-500"
                    />
                 </div>
                 <div className="bg-black/50 p-2 border border-green-900/20 rounded">
                    <span className="text-[8px] block text-green-900 uppercase">Signal Gain</span>
                    <input 
                      type="range" min="0" max="4" step="0.1" 
                      value={filterConfig.gain} 
                      onChange={(e) => setFilterConfig(p => ({ ...p, gain: Number(e.target.value) }))}
                      className="w-full accent-green-500"
                    />
                 </div>
              </div>
            </div>

            <div className="bg-zinc-900 p-4 border border-green-900 rounded flex flex-col justify-between">
              <div className="flex justify-between items-start">
                <h3 className="text-xs font-black text-green-500 uppercase">Capture Module</h3>
                <span className="text-[9px] text-green-900 font-mono">ENCRYPTED_OUT</span>
              </div>
              <button 
                onClick={toggleRecording}
                disabled={!isActive}
                className={`w-full py-4 mt-2 rounded font-black text-sm tracking-widest border-2 transition-all ${
                  isRecording 
                    ? 'bg-red-500 border-red-400 text-black animate-pulse' 
                    : 'bg-green-500/10 border-green-500 text-green-500 hover:bg-green-500 hover:text-black'
                } disabled:opacity-20`}
              >
                {isRecording ? 'HALT_CAPTURE' : 'EXECUTE_SIGNAL_GRAB'}
              </button>
            </div>
          </div>
        </div>

        {/* Right Column: Log */}
        <div className="xl:col-span-3 flex flex-col gap-4">
          <aside className="bg-zinc-950 border border-green-900/50 rounded flex flex-col flex-1 overflow-hidden">
            <div className="p-3 bg-zinc-900 border-b border-green-900 flex justify-between items-center">
              <span className="text-[10px] font-black text-green-500">INTERCEPT_LOG</span>
              <div className="w-2 h-2 bg-green-500 rounded-full" />
            </div>
            <div className="flex-1 overflow-y-auto p-3 space-y-3 custom-scrollbar">
              {recordings.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-green-900/30 italic text-[10px]">
                  <p>NO SIGNALS BUFFERED</p>
                </div>
              ) : (
                recordings.map((rec) => (
                  <div key={rec.id} className="bg-zinc-900 border border-green-900/30 p-3 rounded hover:border-green-500 transition-colors">
                    <div className="flex justify-between items-center mb-2">
                      <span className="text-[9px] font-mono font-bold text-green-500">{rec.id}</span>
                      <button 
                        onClick={() => runAnalysis(rec)}
                        className="text-[8px] bg-green-900/50 hover:bg-green-500 hover:text-black px-2 py-0.5 rounded uppercase font-bold border border-green-500/30 transition-all"
                      >
                        {analyzingId === rec.id ? 'EXTRACTING...' : 'DECODE'}
                      </button>
                    </div>
                    <audio src={rec.url} controls className="w-full h-8 grayscale contrast-150 brightness-75 invert mt-1" />
                    {rec.analysis && (
                      <div className="mt-2 text-[9px] font-mono text-green-400/80 bg-black/50 p-2 rounded border-l-2 border-green-500">
                        <span className="text-green-600 block mb-1">DECRYPTED_INTEL:</span>
                        {rec.analysis}
                      </div>
                    )}
                  </div>
                ))
              )}
            </div>
          </aside>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: #000; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #004400; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #00ff00; }
      `}</style>
    </div>
  );
};

export default App;
